#include <memory>

class MyClass {
public:
    MyClass() = default;
    ~MyClass() = default;
    void doWork() const {}
};

void useSmartPointer() {
    auto ptr = std::make_unique<MyClass>();
    ptr->doWork();
} // ptr自动释放

void useSharedPointer() {
    auto ptr = std::make_shared<MyClass>();
    auto ptr2 = ptr; // 共享所有权
} // 引用计数归零时释放
